param([string]$OutputDirectory,[string]$PdfPath)
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop';if(!$OutputDirectory){$OutputDirectory=if($PdfPath){Split-Path $PdfPath}else{[IO.Path]::GetFullPath((Join-Path $PSScriptRoot '..\..\artifacts\manual'))}};$pdf=if($PdfPath){$PdfPath}else{Join-Path $OutputDirectory 'Manual_Gestudio_Usuarios_Nuevos.pdf'};$html=Join-Path $OutputDirectory 'manual.html';$meta=Join-Path $OutputDirectory 'metadata.json';foreach($f in @($pdf,$html,$meta)){if(!(Test-Path $f)){throw "No existe: $f"}};$b=[IO.File]::ReadAllBytes($pdf);if($b.Length-lt 10000-or[Text.Encoding]::ASCII.GetString($b,0,4)-ne'%PDF'){throw 'PDF inválido.'};$md=Get-Content $meta -Raw|ConvertFrom-Json;if($md.screenshotCount-lt 1){throw 'No hay capturas.'};$repo=[IO.Path]::GetFullPath((Join-Path $PSScriptRoot '..\..'));$mf=Get-Content (Join-Path $repo 'docs\manual-usuarios\manifest.json') -Raw|ConvertFrom-Json;$ids=@($mf.items.id);if(($ids|Sort-Object -Unique).Count-ne$ids.Count){throw 'IDs duplicados.'};$text=(Get-Content $html -Raw)+(Get-Content $meta -Raw);foreach($s in @('Authorization','Bearer ','JWT_SECRET','PASSWORD=')){if($text.Contains($s)){throw "Texto sensible: $s"}};foreach($p in @('artifacts/manual/','docs/manual-usuarios/screenshots/','playwright-report/','test-results/')){git -C $repo check-ignore -q $p;if($LASTEXITCODE-ne 0){throw "Ruta no ignorada: $p"}};Write-Host 'Validación estructural aprobada. La revisión visual humana sigue siendo obligatoria.'